package com.rideshare.matching_service.Service;

import com.rideshare.matching_service.Client.LocationServiceClient;
import com.rideshare.matching_service.DTO.NearByDriverResponse;
import com.rideshare.matching_service.Event.RideMatchedEvent;
import com.rideshare.matching_service.Event.RideRequestedEvent;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

import java.util.Comparator;
import java.util.List;
import java.util.Optional;

@Service
@Slf4j
@RequiredArgsConstructor
public class MatchingService {

    private final KafkaTemplate<String, RideMatchedEvent> kafkaTemplate;
    private static final String RIDE_MATCHED_TOPIC = "ride.matched";
    private static final double DEFAULT_SEARCH_RADIUS_KM = 5.0;
    private final LocationServiceClient locationServiceClient;

    /**
     * Main matching algorithm
     * Called when RideRequestedEvent is consumed from Kafka
     * @param event
     *
     * STEPS:
     * 1. Ask Location Service for nearby drivers
     * 2. Score each driver and pick the best one
     * 3. Publish RideMatchedEvent to Kafka
     */

    public void matchDriverForRide(RideRequestedEvent event){

        List<NearByDriverResponse> nearbyDrivers = locationServiceClient.getNearByDriver(
                event.getPickupLatitude(),
                event.getPickupLongitude(),
                DEFAULT_SEARCH_RADIUS_KM
        );

        if(nearbyDrivers.isEmpty()){
            log.warn("No nearby drivers found for ride");
            return;
        }

        //STEPS 2: Score each driver and pick the best one
        Optional<NearByDriverResponse> bestDriver = findBestDriver(nearbyDrivers);

        if(bestDriver.isEmpty()){
            log.warn("No suitable driver found for ride");
            return;
        }

        NearByDriverResponse assignedDriver = bestDriver.get();

        //STEP 3: Publish RideMatchedEvent to Kafka
        RideMatchedEvent matchedEvent = new RideMatchedEvent(
                event.getRideId(),
                event.getRiderId(),
                assignedDriver.getDriverId(),
                assignedDriver.getLatitude(),
                assignedDriver.getLongitude(),
                assignedDriver.getDistanceInKm()
        );

        kafkaTemplate.send(RIDE_MATCHED_TOPIC, event.getRideId(), matchedEvent);
        log.info("RideMatchedEvent published");
    }

    /**
     * Driver Scoring algorithm
     *
     * Distance: 70%
     *
     * Rating: 30%
     *
     * Score: (1 / (1 + distanceInKm)) * 0.7 + (rating / 5.0) * 0.3
     * @param drivers
     * @return
     */



    private Optional<NearByDriverResponse> findBestDriver(
        List<NearByDriverResponse> drivers){

        double distanceWeight = 0.7;
        double ratingWeight = 0.3;

        return drivers.stream()
                .max(Comparator.comparingDouble(driver ->{
                    //Distance score: closer = higher score
                    //Add 0.1 to avoid division by zero

                    double distanceScore = 1.0 / (driver.getDistanceInKm() + 0.1);

                    // Simulated rating between 4.0 and 5.0
                    // In production: fetch from Driver Service

                    double simulatedRating = 4.0 + Math.random();

                    //Final weighted score
                    return (distanceScore * distanceWeight)
                            + (simulatedRating * ratingWeight);
                }));

    }


























}

package com.rideshare.matching_service.Service;

import com.rideshare.matching_service.Client.LocationServiceClient;
import com.rideshare.matching_service.DTO.NearByDriverResponse;
import com.rideshare.matching_service.Event.RideMatchedEvent;
import com.rideshare.matching_service.Event.RideRequestedEvent;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

import java.util.Comparator;
import java.util.List;
import java.util.Optional;

@Service
@Slf4j
@RequiredArgsConstructor
public class MatchingService {

    private final KafkaTemplate<String, RideMatchedEvent> kafkaTemplate;
    private static final String RIDE_MATCHED_TOPIC = "ride.matched";
    private static final double DEFAULT_SEARCH_RADIUS_KM = 5.0;
    private final LocationServiceClient locationServiceClient;

    /**
     * Main matching algorithm
     * Called when RideRequestedEvent is consumed from Kafka
     * @param event
     *
     * STEPS:
     * 1. Ask Location Service for nearby drivers
     * 2. Score each driver and pick the best one
     * 3. Publish RideMatchedEvent to Kafka
     */

    public void matchDriverForRide(RideRequestedEvent event){
        log.info("Starting ride matching for rideId: {}, location: ({}, {})", 
                event.getRideId(), event.getPickupLatitude(), event.getPickupLongitude());

        List<NearByDriverResponse> nearbyDrivers = locationServiceClient.getNearByDriver(
                event.getPickupLatitude(),
                event.getPickupLongitude(),
                DEFAULT_SEARCH_RADIUS_KM
        );

        log.info("Found {} nearby drivers for rideId: {}", nearbyDrivers.size(), event.getRideId());

        if(nearbyDrivers.isEmpty()){
            log.warn("No nearby drivers found for ride: {}", event.getRideId());
            return;
        }

        //STEPS 2: Score each driver and pick the best one
        Optional<NearByDriverResponse> bestDriver = findBestDriver(nearbyDrivers);

        if(bestDriver.isEmpty()){
            log.warn("No suitable driver found for ride: {}", event.getRideId());
            return;
        }

        NearByDriverResponse assignedDriver = bestDriver.get();

        //STEP 3: Publish RideMatchedEvent to Kafka
        RideMatchedEvent matchedEvent = new RideMatchedEvent(
                event.getRideId(),
                event.getRiderId(),
                assignedDriver.getDriverId(),
                assignedDriver.getLatitude(),
                assignedDriver.getLongitude(),
                assignedDriver.getDistanceInKm()
        );

        log.info("Publishing ride matched event. RideId: {}, DriverId: {}, Distance: {} km",
                event.getRideId(), assignedDriver.getDriverId(), assignedDriver.getDistanceInKm());

        kafkaTemplate.send(RIDE_MATCHED_TOPIC, event.getRideId(), matchedEvent);
        log.info("RideMatchedEvent published successfully for rideId: {}", event.getRideId());
    }

    /**
     * Driver Scoring algorithm
     *
     * Distance: 70%
     *
     * Rating: 30%
     *
     * Score: (1 / (1 + distanceInKm)) * 0.7 + (rating / 5.0) * 0.3
     * @param drivers
     * @return
     */



    private Optional<NearByDriverResponse> findBestDriver(
        List<NearByDriverResponse> drivers){

        double distanceWeight = 0.7;
        double ratingWeight = 0.3;

        return drivers.stream()
                .max(Comparator.comparingDouble(driver ->{
                    //Distance score: closer = higher score
                    //Add 0.1 to avoid division by zero

                    double distanceScore = 1.0 / (driver.getDistanceInKm() + 0.1);

                    // Simulated rating between 4.0 and 5.0
                    // In production: fetch from Driver Service

                    double simulatedRating = 4.0 + Math.random();

                    //Final weighted score
                    return (distanceScore * distanceWeight)
                            + (simulatedRating * ratingWeight);
                }));

    }


























}

package com.rideshare.matching_service.Service;

import com.rideshare.matching_service.Event.RideRequestedEvent;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

@Service
@Slf4j
@RequiredArgsConstructor
public class RideEventConsumer {

    private final MatchingService matchingService;

    /**
     * Listens to ride.requested kafka topic.
     * Triggered every time Ride Service published a new ride request
     *
     * FLOW:
     * Ride Service -> Kafka (ride.requested) -> This Consumer -> MatchingService
     */

    @KafkaListener(
            topics = "ride.requested",
            groupId = "matching-service-group"
    )
    public void consumeRideRequestedEvent(RideRequestedEvent event){
        try{
            matchingService.matchDriverForRide(event);
        }
        catch (Exception e){
            log.error("Error processing ride request: {} - {}",
                    event.getRideId(), e.getMessage());

            // In production: send to dead letter queue for retry
        }
    }
}

package com.rideshare.matching_service.Service;

import com.rideshare.matching_service.Event.RideRequestedEvent;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

@Service
@Slf4j
@RequiredArgsConstructor
public class RideEventConsumer {

    private final MatchingService matchingService;

    /**
     * Listens to ride.requested kafka topic.
     * Triggered every time Ride Service published a new ride request
     *
     * FLOW:
     * Ride Service -> Kafka (ride.requested) -> This Consumer -> MatchingService
     */

    @KafkaListener(
            topics = "ride.requested",
            groupId = "matching-service-group"
    )
    public void consumeRideRequestedEvent(RideRequestedEvent event){
        try{
            if(event == null) {
                log.error("Received null ride requested event");
                return;
            }

            log.info("Processing ride requested event. RideId: {}, Rider: {}", 
                    event.getRideId(), event.getRiderId());

            matchingService.matchDriverForRide(event);

            log.info("Ride matching completed for rideId: {}", event.getRideId());
        }
        catch (Exception e){
            log.error("Error processing ride request: {} - {}", 
                    event != null ? event.getRideId() : "unknown", 
                    e.getMessage(), e);

            // In production: send to dead letter queue for retry
        }
    }
}

package com.rideshare.ride_service.Service;

import com.rideshare.ride_service.Event.RideMatchedEvent;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

@Service
@Slf4j
@RequiredArgsConstructor
public class RideEventConsumer {

    private final RideService rideService;

    @KafkaListener(
            topics = "ride.matched",
            groupId = "ride-service-group"
    )
    public void consumeRideMatchedEvent(RideMatchedEvent event){

        log.info("Received ride matched event: {}", event);

        rideService.updateRideWithDriver(
                event.getRideId(),
                event.getDriverId()
        );
    }
}

package com.rideshare.ride_service.Service;

import com.rideshare.ride_service.Event.RideMatchedEvent;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

@Service
@Slf4j
@RequiredArgsConstructor
public class RideEventConsumer {

    private final RideService rideService;

    @KafkaListener(
            topics = "ride.matched",
            groupId = "ride-service-group"
    )
    public void consumeRideMatchedEvent(RideMatchedEvent event){

        log.info("Received ride matched event: {}", event);

        try {
            if(event == null) {
                log.error("Received null event");
                return;
            }

            log.info("Processing ride matched event for rideId: {}, driverId: {}", 
                    event.getRideId(), event.getDriverId());

            rideService.updateRideWithDriver(
                    event.getRideId(),
                    event.getDriverId()
            );

            log.info("Successfully updated ride with driver");
        } catch (Exception e) {
            log.error("Error processing ride matched event. RideId: {}, Error: {}", 
                    event != null ? event.getRideId() : "unknown", 
                    e.getMessage(), e);
        }
    }
}

package com.rideshare.ride_service.Service;


import com.rideshare.ride_service.DTO.RideRequest;
import com.rideshare.ride_service.DTO.RideResponse;
import com.rideshare.ride_service.Event.RideRequestEvent;
import com.rideshare.ride_service.Mappers.RideMapper;
import com.rideshare.ride_service.Model.Ride;
import com.rideshare.ride_service.Model.RideStatus;
import com.rideshare.ride_service.Repository.RideRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.List;

@Service
@Slf4j
@RequiredArgsConstructor
public class RideService {

    private final RideRepository rideRepository;
    private final KafkaTemplate<String, RideRequestEvent> kafkaTemplate;

    private static final String RIDE_REQUEST_TOPIC = "ride.requested";

    /**
     * create ride in DB with REQUESTED STATUS
     */

    public RideResponse requestRide(RideRequest rideRequest){
        log.info("Processing ride request for rider: {}", rideRequest.getRiderId());

        Ride ride = RideMapper.toEntity(rideRequest);

        Ride saveRide = rideRepository.save(ride);

        //Step 2: publish even to Kafka
        //Matching service will consume this and find nearest driver

        RideRequestEvent event = new RideRequestEvent(
                saveRide.getId(),
                saveRide.getRiderId(),
                saveRide.getPickupLatitude(),
                saveRide.getPickupLongitude(),
                saveRide.getPickupAddress(),
                saveRide.getDropLatitude(),
                saveRide.getDropLongitude(),
                saveRide.getDropAddress()
        );

        kafkaTemplate.send(RIDE_REQUEST_TOPIC,saveRide.getId(), event);
        log.info("Ride request event published to Kafka for rideId: {}", saveRide.getId());

        //update status to Matching
        saveRide.setStatus(RideStatus.MATCHING);
        rideRepository.save(saveRide);

        return  RideMapper.toResponse(saveRide);
    }


    public void updateRideWithDriver(String rideId, String driverId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        ride.setDriverId(driverId);
        ride.setStatus(RideStatus.ACCEPTED);
        rideRepository.save(ride);
    }


    public  RideResponse startRide(String rideId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        if(ride.getStatus() != RideStatus.ACCEPTED){
            throw new RuntimeException("Ride cannot be started. Current status: " + ride.getStatus());
        }

        ride.setStatus(RideStatus.RIDE_STARTED);
        ride.setStartedAt(LocalDateTime.now());

        rideRepository.save(ride);

        return RideMapper.toResponse(ride);
    }

    public RideResponse completeRide(String rideId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        if(ride.getStatus() != RideStatus.RIDE_STARTED){
            throw new RuntimeException("Ride cannot be completed. Current status: " + ride.getStatus());
        }

        ride.setStatus(RideStatus.COMPLETED);
        ride.setCompletedAt(LocalDateTime.now());
        ride.setActualFare(ride.getEstimatedFare());

        rideRepository.save(ride);

        return RideMapper.toResponse(ride);
    }

    public RideResponse cancelRide(String rideId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        ride.setStatus(RideStatus.CANCELLED);
        rideRepository.save(ride);

        return RideMapper.toResponse(ride);
    }

    public RideResponse getRideById(String rideId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        return RideMapper.toResponse(ride);
    }

    public List<RideResponse> getRidesByRider(String riderId){

        return rideRepository.findByRiderIdOrderByCreatedAtDesc(riderId)
                .stream()
                .map(RideMapper::toResponse)
                .toList();
    }




















}

package com.rideshare.ride_service.Service;


import com.rideshare.ride_service.DTO.RideRequest;
import com.rideshare.ride_service.DTO.RideResponse;
import com.rideshare.ride_service.Event.RideRequestEvent;
import com.rideshare.ride_service.Mappers.RideMapper;
import com.rideshare.ride_service.Model.Ride;
import com.rideshare.ride_service.Model.RideStatus;
import com.rideshare.ride_service.Repository.RideRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.List;

@Service
@Slf4j
@RequiredArgsConstructor
public class RideService {

    private final RideRepository rideRepository;
    private final KafkaTemplate<String, RideRequestEvent> kafkaTemplate;

    private static final String RIDE_REQUEST_TOPIC = "ride.requested";

    /**
     * create ride in DB with REQUESTED STATUS
     */

    public RideResponse requestRide(RideRequest rideRequest){
        log.info("Processing ride request for rider: {}", rideRequest.getRiderId());

        Ride ride = RideMapper.toEntity(rideRequest);

        Ride saveRide = rideRepository.save(ride);

        //Step 2: publish even to Kafka
        //Matching service will consume this and find nearest driver

        RideRequestEvent event = new RideRequestEvent(
                saveRide.getId(),
                saveRide.getRiderId(),
                saveRide.getPickupLatitude(),
                saveRide.getPickupLongitude(),
                saveRide.getPickupAddress(),
                saveRide.getDropLatitude(),
                saveRide.getDropLongitude(),
                saveRide.getDropAddress()
        );

        kafkaTemplate.send(RIDE_REQUEST_TOPIC,saveRide.getId(), event);
        log.info("Ride request event published to Kafka for rideId: {}", saveRide.getId());

        //update status to Matching
        saveRide.setStatus(RideStatus.MATCHING);
        rideRepository.save(saveRide);

        return  RideMapper.toResponse(saveRide);
    }


    @Transactional
    public void updateRideWithDriver(String rideId, String driverId){
        log.info("Attempting to update ride with driverId. RideId: {}, DriverId: {}", rideId, driverId);

        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: " + rideId));

        log.info("Found ride. Current status: {}, Current driverId: {}", ride.getStatus(), ride.getDriverId());

        ride.setDriverId(driverId);
        ride.setStatus(RideStatus.ACCEPTED);

        Ride updatedRide = rideRepository.save(ride);

        log.info("Ride updated successfully. New status: {}, New driverId: {}", 
                updatedRide.getStatus(), updatedRide.getDriverId());
    }


    public  RideResponse startRide(String rideId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        if(ride.getStatus() != RideStatus.ACCEPTED){
            throw new RuntimeException("Ride cannot be started. Current status: " + ride.getStatus());
        }

        ride.setStatus(RideStatus.RIDE_STARTED);
        ride.setStartedAt(LocalDateTime.now());

        rideRepository.save(ride);

        return RideMapper.toResponse(ride);
    }

    public RideResponse completeRide(String rideId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        if(ride.getStatus() != RideStatus.RIDE_STARTED){
            throw new RuntimeException("Ride cannot be completed. Current status: " + ride.getStatus());
        }

        ride.setStatus(RideStatus.COMPLETED);
        ride.setCompletedAt(LocalDateTime.now());
        ride.setActualFare(ride.getEstimatedFare());

        rideRepository.save(ride);

        return RideMapper.toResponse(ride);
    }

    public RideResponse cancelRide(String rideId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        ride.setStatus(RideStatus.CANCELLED);
        rideRepository.save(ride);

        return RideMapper.toResponse(ride);
    }

    public RideResponse getRideById(String rideId){
        Ride ride = rideRepository.findById(rideId)
                .orElseThrow(() -> new RuntimeException("Ride not found with id: "));

        return RideMapper.toResponse(ride);
    }

    public List<RideResponse> getRidesByRider(String riderId){

        return rideRepository.findByRiderIdOrderByCreatedAtDesc(riderId)
                .stream()
                .map(RideMapper::toResponse)
                .toList();
    }




















}
